import csv, re
from collections import Counter, defaultdict

def classify(title: str) -> tuple[str, str]:
    """Return (fy, subtype) for an Approp title. fy in {FY26, FY27, FY??}."""
    t = title.strip()
    tl = t.lower().replace("\u2019", "'").replace("\ufffd", "'")

    # Trailer detection first (takes precedence — trailers are structural companions)
    if re.search(r"\b(trailer|trlr|tlr)\b", tl):
        # Trailers inherit the FY of their host, usually FY27; keep flexible
        if "fy 2026" in tl or "fy26" in tl:
            return ("FY26", "Trailer")
        return ("FY27", "Trailer")

    # Reduction / rescissions
    if "reduction" in tl or "rescission" in tl:
        if "fy 2026" in tl or "fy26" in tl:
            return ("FY26", "Reduction")
        return ("FY??", "Reduction")  # unexpected; flag

    # Maintenance (always FY27 in a 2026 session)
    if re.search(r"fy.?2027.?maint", tl) or re.search(r"\bmaint\b", tl):
        return ("FY27", "Maintenance")

    # Explicit FY26 supplemental
    if "fy 2026" in tl or "fy26" in tl:
        return ("FY26", "Supplemental")

    # Explicit FY27 — enhancement
    if "fy 2027" in tl or "fy27" in tl:
        return ("FY27", "Enhancement")

    # Default: no FY stamp → FY27 Enhancement (per LAF rule)
    return ("FY27", "Enhancement")


buckets: dict[tuple[str, str], list[tuple[str, str, str]]] = defaultdict(list)
with open("minidata.csv", "r", encoding="cp1252", newline="") as f:
    for row in csv.reader(f):
        if len(row) < 3:
            continue
        title = row[1].strip()
        if not title.startswith("Approp,"):
            continue
        bill = row[0].strip().upper()
        status = row[2].strip()
        fy, subtype = classify(title)
        buckets[(fy, subtype)].append((bill, status, title))

total = sum(len(v) for v in buckets.values())
print(f"Total Approp bills classified: {total}")
print()

order = [
    ("FY27", "Maintenance"),
    ("FY27", "Enhancement"),
    ("FY27", "Trailer"),
    ("FY26", "Supplemental"),
    ("FY26", "Reduction"),
    ("FY26", "Trailer"),
    ("FY??", "Reduction"),
]
for key in order:
    bills = buckets.get(key, [])
    if not bills:
        continue
    fy, subtype = key
    print(f"=== {fy} / {subtype}  ({len(bills)}) ===")
    for bill, status, title in sorted(bills):
        print(f"  {bill}  [{status}]  {title}")
    print()

# Summary
print("SUMMARY")
counts = Counter({k: len(v) for k, v in buckets.items()})
for key in order:
    if counts.get(key):
        print(f"  {key[0]} {key[1]:<14} {counts[key]}")
EOF
